#define fp float
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
	fp x, y, z;
} THREE_VECTOR;

typedef struct {
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str {
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str {
	fp alpha;
} par_str;

typedef struct dim_str {
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(par_str par,
                                 dim_str dim,
                                 __global box_str* box,
                                 __global FOUR_VECTOR* rv,
                                 __global fp* qv,
                                 __global FOUR_VECTOR* fv) {
	int l = get_group_id(0);
	int i = get_local_id(0);

	if ((long)l >= dim.number_boxes || i >= NUMBER_PAR_PER_BOX) {
		return;
	}

	fp alpha = par.alpha;
	fp a2 = 2.0f * alpha * alpha;

	long first_i = box[l].offset;
	FOUR_VECTOR rA = rv[first_i + i];
	FOUR_VECTOR fA = fv[first_i + i];

	for (int k = 0; k < (1 + box[l].nn); k++) {
		int pointer = (k == 0) ? l : box[l].nei[k - 1].number;
		long first_j = box[pointer].offset;

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
			FOUR_VECTOR rB = rv[first_j + j];
			fp qB = qv[first_j + j];

			fp r2 = rA.v + rB.v - DOT(rA, rB);
			fp u2 = a2 * r2;
			fp vij = exp(-u2);
			fp fs = 2.0f * vij;

			fp dx = rA.x - rB.x;
			fp dy = rA.y - rB.y;
			fp dz = rA.z - rB.z;

			fp fxij = fs * dx;
			fp fyij = fs * dy;
			fp fzij = fs * dz;

			fA.v += qB * vij;
			fA.x += qB * fxij;
			fA.y += qB * fyij;
			fA.z += qB * fzij;
		}
	}

	fv[first_i + i] = fA;
}
